import { useContext, useEffect, useState } from "react";
import { AuthContext } from "./AuthContext";
import ClubHeader from "./ClubHeader";
import ClubMain from "./components/Clubs/ClubMain";

export default function ClubDetail() {
    const { user } = useContext(AuthContext);

    const match = (window.location.hash || "").match(/^#\/clubs\/(\d+)(?:\/(\w+))?/);
    const clubId = match ? Number(match[1]) : null;
    const activeTab = match?.[2] || "overview";

    const [club, setClub] = useState(null);
    const [members, setMembers] = useState([]);
    const [news, setNews] = useState([]);

    useEffect(() => {
        if (!clubId) return;

        fetch(`/api/clubs/${clubId}`).then(r => r.json()).then(setClub);
        fetch(`/api/clubs/${clubId}/members`).then(r => r.json()).then(setMembers);
        fetch(`/api/clubs/${clubId}/news`).then(r => r.json()).then(setNews);
    }, [clubId]);

    if (!club) return <div>Loading…</div>;

    const isLeader = members.some(m => m.userId === user?.id && m.role === "LEADER");

    return (
        <div className="page">
            <ClubHeader
                club={club}
                activeTab={activeTab}
                leaders={members.filter(m => m.role === "LEADER").map(m => `User #${m.userId}`)}
                membership={{
                    isMember: members.some(m => m.userId === user?.id),
                    isLeader,
                    hasPending: false
                }}
            />

            <ClubMain
                tab={activeTab}
                club={club}
                members={members}
                news={news}
                isLeader={isLeader}
                user={user}
            />
        </div>
    );
}
